package com.example.app.waitlist; import com.example.app.common.BaseEntity; import com.example.app.company.Company; import com.example.app.session.SessionBooking; import com.example.app.user.User; import jakarta.persistence.*; import lombok.Getter; import lombok.Setter; import java.time.*; @Getter @Setter @Entity @Table(name="booking_hold") public class BookingHold extends BaseEntity { @ManyToOne(optional=false) @JoinColumn(name="company_id") private Company company; @Column(name="slot_start",nullable=false) private LocalDateTime slotStart; @Column(name="slot_end",nullable=false) private LocalDateTime slotEnd; @ManyToOne @JoinColumn(name="employee_id") private User employee; @Column(name="room_id") private Long roomId; @ManyToOne @JoinColumn(name="session_id") private SessionBooking session; @Column(nullable=false,length=32) private String status="ACTIVE"; @Column(name="expires_at",nullable=false) private LocalDateTime expiresAt; @Column(name="override_allowed",nullable=false) private boolean overrideAllowed=true; @Version private Long version; }